export interface CartLine { sku: string; qty: number; addedAt: number }

export function dedupeCart(lines: CartLine[]): CartLine[] {
  const out: CartLine[] = [];
  for (const line of lines) {
    const existing = out.find(o => o.sku === line.sku);
    if (existing) {
      existing.qty += line.qty;
      existing.addedAt = Math.min(existing.addedAt, line.addedAt);
    } else {
      out.push({ ...line });
    }
  }
  return out;
}
